// ============================================================
// Generate Apify Google Maps scraping tasks for DMV service businesses
// ============================================================

const businessTypes = [
  'Roofing companies',
  'HVAC contractors',
  'Plumbers',
  'General contractors',
  'Remodelers',
  'Dental clinics',
  'Law firms',
  'Real estate agencies',
  'Insurance agencies',
  'Landscaping companies',
  'Auto repair shops',
  'Med spas',
  'Aesthetic clinics',
  'Cleaning services'
];

const dmvLocations = [
  'Washington DC',
  'Arlington VA',
  'Alexandria VA',
  'Fairfax VA',
  'Bethesda MD',
  'Rockville MD',
  'Silver Spring MD',
  'Gaithersburg MD',
  'Silver Spring MD',
  'Frederick MD',
  'Germantown MD',
  'Reston VA',
  'Ashburn VA',
  'Manassas VA',
  'Annapolis MD',
  'Bowie MD',
  'College Park MD',
  'Falls Church VA',
  'McLean VA',
  'Vienna VA'
];

// Generate search queries: each business type × each DMV location
const searchQueries = [];
for (const type of businessTypes) {
  for (const location of dmvLocations) {
    searchQueries.push(`${type} in ${location}`);
  }
}

// Return as individual items for n8n split-batch processing
return searchQueries.map(query => ({
  json: {
    searchQuery: query,
    businessType: query.split(' in ')[0],
    city: query.split(' in ')[1],
    batch_id: $input.first().json.batch_id
  }
}));

// ============================================================
// Normalize and merge results from Google Maps + Yelp
// Standardize schema, discard leads missing email
// ============================================================

const items = $input.all();
const merged = [];

for (const item of items) {
  const data = item.json;

  // Detect source
  const source = data.source || (data.url?.includes('yelp') ? 'yelp' : 'google_maps');

  // Extract email — try multiple fields
  const email = (
    data.email ||
    data.emails?.[0] ||
    data.contactEmail ||
    ''
  ).trim().toLowerCase();

  // DISCARD if no email
  if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
    continue;
  }

  // Extract business type from the search query context
  const businessType = (item.json.businessType || data.category || 'unknown').toLowerCase();
  const city = (item.json.city || data.city || 'DMV').trim();

  merged.push({
    json: {
      business_name: (data.name || data.businessName || data.title || '').trim(),
      owner_name: data.ownerName || data.contactName || null,
      email: email,
      phone: (data.phone || data.phoneNumber || data.tel || '').trim(),
      website: (data.web || data.website || data.url || '').trim(),
      business_type: businessType,
      city: city,
      google_rating: parseFloat(data.rating || data.stars || 0),
      review_count: parseInt(data.reviewCount || data.reviews || data.numberOfReviews || 0),
      source: source,
      address: (data.address || data.fullAddress || '').trim(),
      _scraped_at: new Date().toISOString()
    }
  });
}

return merged;

// ============================================================
// Deduplicate leads by email address
// Keep the record with the most data (most non-empty fields)
// ============================================================

const items = $input.all();
const seen = new Map();

for (const item of items) {
  const email = item.json.email;
  if (!email) continue;

  const existing = seen.get(email);
  if (!existing) {
    seen.set(email, item);
    continue;
  }

  // Count non-empty fields for each
  const countFields = (obj) => Object.values(obj).filter(v => v && v !== '' && v !== null).length;
  const existingScore = countFields(existing.json);
  const newScore = countFields(item.json);

  // Keep the richer record
  if (newScore > existingScore) {
    seen.set(email, item);
  }
}

return Array.from(seen.values());

// ============================================================
// Enrich leads with website contact data
// ============================================================

const websiteData = $input.first().json;
const leadData = $('Deduplicate by Email').first().json;

// Extract owner name from website content if not already known
let ownerName = leadData.owner_name;
if (!ownerName && websiteData) {
  // Try common patterns: "Owner: John Smith", "Founded by", etc.
  const pageText = (websiteData.text || websiteData.content || '');
  const ownerMatch = pageText.match(/(?:owner|founder|president|ceo)\s*[:;]\s*([A-Z][a-z]+\s+[A-Z][a-z]+)/i);
  if (ownerMatch) {
    ownerName = ownerMatch[1].trim();
  }
}

// Enrich email from website if we found a better one
let email = leadData.email;
if (websiteData.emails && websiteData.emails.length > 0) {
  // Prefer generic@domain or info@domain over personal emails
  const genericEmail = websiteData.emails.find(e => 
    /^(info|contact|hello|office|front)/i.test(e.split('@')[0])
  );
  if (genericEmail) {
    email = genericEmail.toLowerCase();
  }
}

return [{
  json: {
    ...leadData,
    owner_name: ownerName,
    email: email,
    website_contact_emails: websiteData.emails || [],
    website_contact_phones: websiteData.phoneNumbers || [],
    _enriched_at: new Date().toISOString()
  }
}];

