// ============================================================
// Parse OpenClaw scoring response
// ============================================================

const raw = $input.first().json.response || $input.first().json.content || '';
const cleaned = raw.replace(/```json\s*/g, '').replace(/```/g, '').trim();

try {
  const parsed = JSON.parse(cleaned);
  const leadData = $('Enrich Website Contact Data').first().json;

  if (typeof parsed.score !== 'number' || parsed.score < 0 || parsed.score > 10) {
    throw new Error(`Invalid score: ${parsed.score}`);
  }

  return [{
    json: {
      ...leadData,
      score: parsed.score,
      reasoning: parsed.reasoning || '',
      pain_point: parsed.pain_point || '',
      personalization_hook: parsed.personalization_hook || ''
    }
  }];
} catch (e) {
  throw new Error(`Failed to parse scoring response: ${e.message}`);
}

// ============================================================
// Parse email from OpenClaw output — extract subject and body
// ============================================================

const raw = $input.first().json.response || $input.first().json.content || '';

// Split on "Subject:" or "Subject :" pattern
const subjectMatch = raw.match(/Subject:\s*(.+?)(?:\n|$)/i);
const subject = subjectMatch ? subjectMatch[1].trim() : `Quick question about ${$('Parse Score JSON').first().json.business_name}`;

// Body is everything after the subject line
let body = raw;
if (subjectMatch) {
  body = raw.split(/Subject:\s*.+?\n/i).slice(1).join('\n').trim();
}

// Clean up any markdown code blocks
body = body.replace(/^```/gm, '').trim();

const leadData = $('Parse Score JSON').first().json;

return [{
  json: {
    ...leadData,
    email_subject: subject,
    email_body: body
  }
}];

